class Solution {
    public List<Integer> findSubstring(String s, String[] words) {
        if (s == null || words == null || words.length == 0) return new ArrayList<>();
        Map<String, Integer> wordCount = new HashMap<>();
        for (String word : words) {
            wordCount.put(word, wordCount.getOrDefault(word, 0) + 1);
        }
        int wordLen = words[0].length();
        int totalWords = words.length;
        List<Integer> res = new ArrayList<>();
        for (int i = 0; i <= s.length() - totalWords * wordLen; i++) {
            Map<String, Integer> seen = new HashMap<>();
            for (int j = 0; j < totalWords; j++) {
                int nextIndex = i + j * wordLen;
                String word = s.substring(nextIndex, nextIndex + wordLen);
                if (!wordCount.containsKey(word) || seen.getOrDefault(word, 0) + 1 > wordCount.get(word)) {
                    break;
                }
                seen.put(word, seen.getOrDefault(word, 0) + 1);
                if (j + 1 == totalWords) {
                    res.add(i);
                }
            }
        }
        return res;
    }
}
